using namespace adsk::core;
using namespace adsk::fusion;

Ptr ui;

extern "C" XI_EXPORT bool run(const char* context)
{
    Ptr app = Application::get();
    if (!app)
        return false;

    ui = app->userInterface();
    if (!ui)
        return false;

    Ptr design = app->activeProduct();
    if (!design)
        return false;

    // Get the root component of the active design
    Ptr root = design->rootComponent();
    if (!root)
        return false;

    // Have the edge selected and add it to an ObjectCollection.
    Ptr selection = ui->selectEntity("Select edge to chamfer", "Edges");
    if (!selection)
        return false;

    Ptr edge = selection->entity();
    if (!edge)
        return false;

    Ptr edgeCollection = ObjectCollection::create();
    if (!edgeCollection)
        return false;
    edgeCollection->add(edge);

    Ptr feats = root->features();
    if (!feats)
        return false;

    Ptr chamfers = feats->chamferFeatures();
    if (!chamfers)
        return false;

    Ptr chamferInput = chamfers->createInput(edgeCollection, true);
    if (!chamferInput)
        return false;
    chamferInput->setToEqualDistance(ValueInput::createByReal(1.0));

    Ptr chamfer = chamfers->add(chamferInput);
    return true;
}
